mapper.select:



        FROM housedeals d
        STRAIGHT_JOIN houseinfos h ON d.apt_seq = h.apt_seq
        STRAIGHT_JOIN dongcodes dc ON CONCAT(h.sgg_cd, h.umd_cd) = dc.dong_code








        AND (
            h.apt_nm LIKE #{keywordLike}
            OR dc.sido_name LIKE #{keywordLike}
            OR dc.gugun_name LIKE #{keywordLike}
            OR dc.dong_name LIKE #{keywordLike}
            OR h.umd_nm LIKE #{keywordLike}
        )


        AND dc.sido_name = #{sidoName}


        AND dc.gugun_name = #{gugunName}


        AND (dc.dong_name = #{dongName} OR h.umd_nm = #{dongName})



        AND h.sgg_cd = #{sggCd}


        AND d.deal_year = #{dealYear}


        AND d.deal_year = #{dealYearFromYmd}


        AND d.deal_month = #{dealMonthFromYmd}


ORDER BY d.deal_year DESC, d.deal_month DESC, d.deal_day DESC, d.no DESC
LIMIT #{safeLimit}



WHERE d.no IN

    #{dealNo}

ORDER BY FIELD(d.no,

    #{dealNo}

)
